import { createCampaign } from "@/server/campaigns";
import { useMutation } from "@tanstack/react-query";

export function useCreateCampaign() {
  return useMutation({
    mutationFn: (data: { name: string }) => createCampaign({ data }),
  });
}

import type { SubmitEvent } from "react";
import { useEffect, useState } from "react";
import { useCreateCampaign } from "@/hooks/useCreateCampaign";
import { reportClientError } from "@/lib/reportClientError";
import {
  Button,
  Dialog,
  DialogContent,
  DialogFooter,
  DialogHeader,
  DialogTitle,
  Input,
} from "@workspace/ui";
import { Loader2 } from "lucide-react";
import { Field, FieldLabel } from "./ui/field";

export type CreateCampaignModalProps = {
  navigate: (opts: {
    params: { campaignId: string };
    to: "/campaigns/$campaignId";
  }) => Promise<unknown>;
  onOpenChange: (open: boolean) => void;
  open: boolean;
};

export function CreateCampaignModal({
  navigate,
  onOpenChange,
  open,
}: CreateCampaignModalProps) {
  const [formError, setFormError] = useState<string | null>(null);
  const [formKey, setFormKey] = useState(0);
  const { mutateAsync, isPending } = useCreateCampaign();

  useEffect(() => {
    if (!open) {
      setFormError(null);
      setFormKey((k) => k + 1);
    }
  }, [open]);

  const submitCampaign = async (form: HTMLFormElement) => {
    const formData = new FormData(form);
    const rawName = formData.get("campaignName");
    const trimmedName = typeof rawName === "string" ? rawName.trim() : "";
    if (!trimmedName) {
      return;
    }

    setFormError(null);
    try {
      const campaign = await mutateAsync({ name: trimmedName });

      onOpenChange(false);
      await navigate({
        to: "/campaigns/$campaignId",
        params: { campaignId: campaign.id.toString() },
      });
    } catch (error) {
      const message = "Could not create campaign. Please try again.";
      setFormError(message);
      reportClientError(error, { operation: "createCampaign" }, message);
    }
  };

  const handleFormSubmit = (event: SubmitEvent<HTMLFormElement>) => {
    event.preventDefault();
    void submitCampaign(event.currentTarget);
  };

  return (
    <Dialog onOpenChange={onOpenChange} open={open}>
      <DialogContent
        className="font-outfit sm:max-w-md"
        aria-describedby="create-campaign-modal-description"
      >
        <DialogHeader>
          <DialogTitle>Create campaign</DialogTitle>
        </DialogHeader>

        <form key={formKey} method="post" onSubmit={handleFormSubmit}>
          <div className="flex flex-col gap-4 py-2">
            <Field>
              <FieldLabel htmlFor="create-campaign-modal-name">
                Campaign name
              </FieldLabel>
              <Input
                autoComplete="off"
                className="h-10"
                id="create-campaign-modal-name"
                minLength={1}
                name="campaignName"
                placeholder="e.g. Spring Gala 2026"
                required
              />
            </Field>
            {formError ? (
              <p className="text-destructive text-sm" role="alert">
                {formError}
              </p>
            ) : null}
          </div>

          <DialogFooter className="gap-2 sm:gap-2">
            <Button
              type="button"
              variant="outline"
              onClick={() => onOpenChange(false)}
            >
              Cancel
            </Button>
            <Button disabled={isPending} type="submit">
              {isPending && <Loader2 className="animate-spin" size={16} />}
              {isPending ? "Creating..." : "Create campaign"}
            </Button>
          </DialogFooter>
        </form>
      </DialogContent>
    </Dialog>
  );
}

