import { campaignApiScopeFromTenant } from "@/lib/campaignApiScope";
import { orgApiScopedPath } from "@/lib/orgApiScopedPath";
import type { Tenant } from "@/types/bootstrap";
import type { Campaign } from "@/types/campaign";
import { isNotFound, notFound, redirect } from "@tanstack/react-router";
import { createServerFn } from "@tanstack/react-start";
import { z } from "zod";
import { getAppBootstrapData } from "./appBootstrap";
import { OrgApiError } from "./error";
import { getOrgApiJson, postOrgApiJson, putOrgApiJson } from "./orgApi.server";
import { logServerErrorToRollbar } from "./rollbarServer.server";

async function requireBootstrapWithTenant(): Promise<{
  tenant: Tenant;
} | null> {
  const bootstrap = await getAppBootstrapData();
  const tenant = bootstrap?.currentTenant;
  if (!bootstrap || !tenant) {
    return null;
  }
  return { tenant };
}

function campaignsCollectionPath(tenant: Tenant): string {
  const scope = campaignApiScopeFromTenant(tenant);
  return orgApiScopedPath("/campaigns", scope);
}

function campaignMemberPath(tenant: Tenant, campaignId: string): string {
  const scope = campaignApiScopeFromTenant(tenant);
  return orgApiScopedPath(
    `/campaigns/${encodeURIComponent(campaignId)}`,
    scope,
  );
}

function assertOrgTenantCanCreateCampaign(tenant: Tenant): void {
  if (tenant.tenant_type !== "org") {
    throw new OrgApiError(
      "Only organization workspaces can create campaigns",
      403,
    );
  }
}

export async function fetchCampaignsList(): Promise<Campaign[] | null> {
  const ctx = await requireBootstrapWithTenant();
  if (!ctx) {
    return null;
  }
  return getOrgApiJson<Campaign[]>(campaignsCollectionPath(ctx.tenant));
}

export async function createCampaignForCurrentTenant(
  name: string,
): Promise<Campaign | null> {
  const ctx = await requireBootstrapWithTenant();
  if (!ctx) {
    return null;
  }
  assertOrgTenantCanCreateCampaign(ctx.tenant);
  const path = campaignsCollectionPath(ctx.tenant);
  return postOrgApiJson<Campaign>(path, { campaign: { name } });
}

export async function fetchCampaign(
  campaignId: string,
): Promise<Campaign | null> {
  const ctx = await requireBootstrapWithTenant();
  if (!ctx) {
    return null;
  }
  try {
    return await getOrgApiJson<Campaign>(
      campaignMemberPath(ctx.tenant, campaignId),
    );
  } catch (error) {
    if (error instanceof OrgApiError && error.status === 404) {
      return null;
    }
    throw error;
  }
}

export async function submitUpdateCampaign(
  campaignId: string,
  payload: { name: string },
): Promise<Campaign | null> {
  const ctx = await requireBootstrapWithTenant();
  if (!ctx) {
    return null;
  }
  return putOrgApiJson<Campaign>(campaignMemberPath(ctx.tenant, campaignId), {
    campaign: { name: payload.name },
  });
}

export const listCampaigns = createServerFn({ method: "GET" }).handler(
  async () => {
    return fetchCampaignsList();
  },
);

export const getCampaignDetail = createServerFn({ method: "GET" })
  .inputValidator(
    z.object({
      campaignId: z.string(),
    }),
  )
  .handler(async ({ data }) => {
    try {
      const campaign = await fetchCampaign(data.campaignId);

      if (!campaign) {
        throw notFound();
      }

      return { campaign };
    } catch (error) {
      if (error instanceof OrgApiError && error.status === 401) {
        throw redirect({ to: "/login" });
      }

      if (isNotFound(error)) {
        throw error;
      }

      logServerErrorToRollbar(
        error instanceof Error ? error : new Error(String(error)),
        { serverFn: "getCampaignDetail" },
      );
      throw error;
    }
  });

export const createCampaign = createServerFn({ method: "POST" })
  .inputValidator(
    z.object({
      name: z.string().trim().min(1),
    }),
  )
  .handler(async ({ data }) => {
    try {
      const campaign = await createCampaignForCurrentTenant(data.name);

      if (!campaign) {
        throw new Error("Unable to create campaign");
      }

      return campaign;
    } catch (error) {
      if (error instanceof OrgApiError && error.status === 401) {
        throw redirect({ to: "/login" });
      }

      logServerErrorToRollbar(
        error instanceof Error ? error : new Error(String(error)),
        { serverFn: "createCampaign" },
      );
      throw error;
    }
  });

export const updateCampaign = createServerFn({ method: "POST" })
  .inputValidator(
    z.object({
      campaignId: z.string().trim().min(1),
      name: z.string().trim().min(1),
    }),
  )
  .handler(async ({ data }) => {
    try {
      const campaign = await submitUpdateCampaign(data.campaignId, {
        name: data.name,
      });

      if (!campaign) {
        throw new Error("Unable to update campaign");
      }

      return campaign;
    } catch (error) {
      if (error instanceof OrgApiError && error.status === 401) {
        throw redirect({ to: "/login" });
      }

      logServerErrorToRollbar(
        error instanceof Error ? error : new Error(String(error)),
        { serverFn: "updateCampaign" },
      );
      throw error;
    }
  });

